}
/* UNLOCO map popup: flag top-left, UNLOCO below flag, close space top-right; bold stat lines */
.afw-hub-unloco-popup {
  box-sizing: border-box;
  min-width: 10.5rem;
  max-width: 18rem;
  padding-right: 2.6rem;
  margin: 0;
}
.afw-hub-popup-head {
  display: flex;
  flex-direction: row;
  justify-content: space-between;
  align-items: flex-start;
  gap: 0.5rem;
