    sumEl.textContent = __("No companies");
    return;
  }
  if (!selN || selN === n) {
    sumEl.textContent = __("All companies");
    return;
  }
  if (selN === 1) {
    for (var j = 0; j < cbs.length; j++) {
      if (cbs[j].checked) {
